<template><select class="sc-input" :value="modelValue" :disabled="disabled" :aria-disabled="disabled || undefined" :aria-readonly="readonly || undefined" :aria-required="required || undefined" :aria-invalid="invalid || undefined" :aria-describedby="describedBy" @change="onChange"><slot /></select></template>
<script setup lang="ts">const props=defineProps<{ modelValue:string|number; disabled?:boolean; readonly?:boolean; required?:boolean; invalid?:boolean; describedBy?:string }>(); const emit=defineEmits<{ 'update:modelValue':[value:string] }>(); function onChange(event:Event){const target=event.target as HTMLSelectElement;if(props.readonly){target.value=String(props.modelValue);return;}emit('update:modelValue',target.value);}</script>
